  const recordRef   = useRef<number>(0)
  const timerRef    = useRef<ReturnType<typeof setInterval> | null>(null)
  const timeoutRefs = useRef<ReturnType<typeof setTimeout>[]>([])

  const clearAllTimers = useCallback(() => {
    if (timerRef.current !== null) {
      clearInterval(timerRef.current)
      timerRef.current = null
    }
    timeoutRefs.current.forEach(clearTimeout)
    timeoutRefs.current = []
  }, [])

  useEffect(() => () => clearAllTimers(), [clearAllTimers])

  const startPlaying = useCallback(() => {
    setGameState('playing')
    setCountdownMessage('')
    setTimeLeft(GAME_DURATION)

    let remaining = GAME_DURATION

    timerRef.current = setInterval(() => {
      remaining -= 1
      setTimeLeft(remaining)

      if (remaining <= 0) {
        clearInterval(timerRef.current!)
        timerRef.current = null

        const finalClicks = clicksRef.current
        const newRecord   = finalClicks > recordRef.current

        if (newRecord) {
          recordRef.current = finalClicks
          setRecord(finalClicks)
        }

        setIsNewRecord(newRecord)
        setGameState('finished')
      }
    }, 1000)
  }, [])

  const handleStart = useCallback(() => {
    clearAllTimers()
    clicksRef.current = 0
    setClicks(0)
    setIsNewRecord(false)
    setGameState('countdown')

    COUNTDOWN_STEPS.forEach((msg, i) => {
      const t = setTimeout(() => setCountdownMessage(msg), i * 1000)
      timeoutRefs.current.push(t)
    })

    // "Ya" aparece en (length-1)*1000 = 2000ms, el juego arranca al mismo tiempo
    const startT = setTimeout(startPlaying, (COUNTDOWN_STEPS.length - 1) * 1000)
    timeoutRefs.current.push(startT)
  }, [clearAllTimers, startPlaying])

  const handleClickButton = useCallback(() => {
    if (gameState !== 'playing') return
    clicksRef.current += 1
    setClicks(clicksRef.current)
  }, [gameState])

  const isStartDisabled = gameState === 'countdown' || gameState === 'playing'
  const isClickDisabled = gameState !== 'playing'

  return (
    <div className={styles.container}>
      <h1 className={styles.title}>JuegoContador</h1>

      <div className={styles.record}>
        <span className={styles.recordLabel}>Record</span>
